330	const createExecHarness = (
331	  behavior: (child: FakeProcess) => void,
332	): { readonly exec: ProviderExec; readonly calls: ExecCall[] } => {
333	  const calls: ExecCall[] = [];
334	  const exec: ProviderExec = (command, args, options) => {
335	    const child = new FakeProcess();
336	    calls.push({ command, args, options, child });
337	    behavior(child);
338	    return child;
339	  };
340	
341	  return { exec, calls };
342	};
