353	const makeClock = (values: readonly number[]) => {
354	  let index = 0;
355	
356	  return (): number => {
357	    const value = values[Math.min(index, values.length - 1)];
358	    index += 1;
359	    if (value === undefined) {
360	      throw new Error("clock requires at least one value");
361	    }
362	
363	    return value;
364	  };
365	};
