385	class FakeStream {
386	  private readonly listeners: Array<(chunk: string) => void> = [];
387	
388	  setEncoding(): void {}
389	
390	  on(event: "data", listener: (chunk: string) => void): void {
391	    if (event === "data") {
392	      this.listeners.push(listener);
393	    }
394	  }
395	
396	  emit(chunk: string): void {
397	    for (const listener of this.listeners) {
398	      listener(chunk);
399	    }
400	  }
401	}
402	
403	class FakeProcess implements ProviderProcess {
404	  readonly stdout = new FakeStream();
405	  readonly stderr = new FakeStream();
406	  readonly killSignals: string[] = [];
407	  private readonly errorListeners: Array<(error: Error) => void> = [];
408	  private readonly closeListeners: Array<
409	    (code: number | null, signal: string | null) => void
410	  > = [];
411	
412	  on(event: "error", listener: (error: Error) => void): void;
413	  on(
414	    event: "close",
415	    listener: (code: number | null, signal: string | null) => void,
416	  ): void;
417	  on(
418	    event: "error" | "close",
419	    listener:
420	      | ((error: Error) => void)
421	      | ((code: number | null, signal: string | null) => void),
422	  ): void {
423	    if (event === "error") {
424	      this.errorListeners.push(listener as (error: Error) => void);
425	      return;
426	    }
427	
428	    this.closeListeners.push(
429	      listener as (code: number | null, signal: string | null) => void,
430	    );
431	  }
432	
433	  kill(signal: "SIGTERM"): boolean {
434	    this.killSignals.push(signal);
435	    return true;
436	  }
437	
438	  emitError(error: Error): void {
439	    for (const listener of this.errorListeners) {
440	      listener(error);
441	    }
442	  }
443	
444	  emitClose(code: number | null, signal: string | null): void {
445	    for (const listener of this.closeListeners) {
446	      listener(code, signal);
447	    }
448	  }
449	}
